        } else if plugin_count > 0 {
            tracing::debug!(
                "get_all: {} plugin commands but vi_mode_toggle NOT found",
                plugin_count<response clipped><NOTE>Due to the max output limit, only part of the full response has been shown to you.</NOTE> /// When query is empty, commands are sorted by recency (most recently used first).
