        let json = r#"{
            "action": {
                "copy": "Copy",
                "paste": "Paste"
            },
            "simple": "value"
        }"#;
        let parsed = parse_locale(json);
        assert_eq!(parsed.get("action.copy").copied(), Some("Copy"));
        assert_eq!(parsed.get("action.paste").copied(), Some("Paste"));
        assert_eq!(parsed.get("simple").copied(), Some("value"));
    }

